solution: ```class Solution {
public:
    string lastSubstring(string s) {
        int n = s.size();
        int i = 0, j = 1, k = 0;
        while (i + k < n && j + k < n) {
            if (s[i + k] == s[j + k]) {
                ++k;
                continue;
            }
            if (s[i + k] < s[j + k]) {
                i = i + k + 1;
            } else {
                j = j + k + 1;
            }
            if (i == j) ++j;
            k = 0;
        }
        return s.substr(min(i, j));
    }
};
